import React, { useRef } from "react";

function FocusBox() {
  const inputRef = useRef(null);

  const focusInput = () => {
    inputRef.current.focus();
  };

  return (
    <div className="card">
      <h3>useRef</h3>

      <input ref={inputRef} type="text" placeholder="Clique sur Focus" />

      <button onClick={focusInput}>Focus</button>
    </div>
  );
}

export default FocusBox;
